// Auto-generated publisher watermark (Nahdet Misr logo) injected into every
// hosted flipbook served by /reader/[id]. Books whose HTML already contains
// the marker (nmwm) - i.e. newly generated ones with the baked-in watermark -
// are skipped by the route.
// Light on screen so books stay readable; much stronger when printed.
export const NM_WATERMARK_SNIPPET =
  '<style>#nmwm{position:fixed;inset:0;z-index:2147483000;pointer-events:none;' +
  'background-image:url("data:image/png;base64,");' +
  'background-repeat:space;background-position:center;background-size:auto min(52vmin,300px);opacity:.13}' +
  '@media print{#nmwm{opacity:.55}}</style><div id="nmwm" aria-hidden="true"></div>';
